const authAPI = {
    signup: async (name, email, password, confirmPassword)=>{
        const data = await apiCall('/auth/signup', {
            method: 'POST',
            body: JSON.stringify({
                name,
                email,
                password,
                confirmPassword
            })
        });
        if (data.token) {
            localStorage.setItem('authToken', data.token);
        }
        return data;
    },
    login: async (email, password)=>{
        const data = await apiCall('/auth/login', {
            method: 'POST',
            body: JSON.stringify({
                email,
                password
            })
        });
        if (data.token) {
            localStorage.setItem('authToken', data.token);
        }
        return data;
    },
    getCurrentUser: async ()=>{
        return apiCall('/auth/me');
    },
    logout: ()=>{
        localStorage.removeItem('authToken');
    }
};
const resumeAPI = {
    upload: async (file)=>{
        const token = localStorage.getItem('authToken');
        const formData = new FormData();
        formData.append('resume', file);
        const response = await fetch(`${API_BASE}/resume/upload`, {
            method: 'POST',
            headers: {
                Authorization: `Bearer ${token}`
            },
            body: formData
        });
        if (!response.ok) {
            const error = await response.json();
            throw new Error(error.error || 'Resume upload failed');
        }
        return response.json();
    },
    get: async ()=>{
        return apiCall('/resume');
    }
};
const jobsAPI = {
    getAll: async ()=>{
        return apiCall('/jobs');
    },
    search: async (filters)=>{
        const params = new URLSearchParams();
        if (filters.title) params.append('title', filters.title);
        if (filters.location) params.append('location', filters.location);
        if (filters.minSalary) params.append('minSalary', filters.minSalary);
        return apiCall(`/jobs/search?${params.toString()}`);
    },
    getRecommended: async ()=>{
        return apiCall('/jobs/recommended');
    }
};
const applicationsAPI = {
    apply: async (jobId)=>{
        return apiCall('/applications', {
            method: 'POST',
            body: JSON.stringify({
                jobId
            })
        });
    },
    getMyApplications: async ()=>{
        return apiCall('/applications');
    }
};
const autoApplyAPI = {
    getRules: async ()=>{
        return apiCall('/auto-apply/rules');
    },
    createRule: async (rule)=>{
        return apiCall('/auto-apply/rules', {
            method: 'POST',
            body: JSON.stringify(rule)
        });
    },
    getSettings: async ()=>{
        return apiCall('/settings');
    },
    updateSettings: async (settings)=>{
        return apiCall('/settings', {
            method: 'PUT',
            body: JSON.stringify(settings)
        });
    }
};
const analyticsAPI = {
    getStats: async ()=>{
        return apiCall('/analytics/stats');
    }
};
const seedAPI = {
    seedJobs: async ()=>{
        const response = await fetch(`${API_BASE}/seed-jobs`, {
            method: 'POST'
        });
        return response.json();
    }
};
